var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이게……. 우리들의 첫 게임……. 카운터즈 사가……?","JPN":"これが……僕たちの初のゲーム……カウンターズ・サーガ……？","ENG":"This is... our first game...! Counters Saga…","TWN":"這是……我們的第一個遊戲…… 制裁者傳奇……？"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오호!? 쌔 삥이라 따끈따끈한데? 이 정도면 진짜로 대박 칠 거 같지 않나?","JPN":"おお！？　出来立てほやほややん！　これならホンマに大ヒットしそうやな？","ENG":"Aha! Hot off the press! This is going to be a show stopper for sure!","TWN":"哇喔！？是剛做好的嗎？還熱熱的呢？這應該會大賣吧？"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응응, 너무 귀엽게 나온 거 같아. 역시 박스 군은 대단해!","JPN":"うんうん、とてもかわいくできたと思う。やっぱりダンボール君はすごい！","ENG":"Yes, it’s so cute! You’re awesome, Boxie!","TWN":"嗯嗯，超可愛的，紙箱小朋友真的好厲害！"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하하, 아니에요.","JPN":"はは、とんでもないです。","ENG":"Ha ha, thanks.","TWN":"哈哈，沒有啦。"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"SD 캐릭터는 자신 없었는데…… 그래도 실제로 프린팅된 걸 보니까 그럭저럭 잘 나온 것 같아서 기뻐요.","JPN":"SDキャラは自信なかったんですけど……でも実際にプリントされたのを見ると、まあまあの出来なので嬉しいです。","ENG":"I’m not too confident with SD art styles... But looking at how it got printed out, I guess it’s okay.","TWN":"SD角色我沒什麼把握……不過看到實際呈現後，成果很不錯呢，真開心。"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐라노? 아무나 이렇게 못 그린다 안 카나. 이건 니만 할 수 있는 거라고.","JPN":"何言ってんねん。普通はこうは描けへんて。これはあんたにしかできへんよ。","ENG":"What's that ya say? It ain’t common bein’ able to draw like Picasso! That's somethin’ only you can do, kiddo.","TWN":"說啥呢？這可不是誰都畫得出來的，只有你可以。"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니는 좀 더 자신감을 가져도 된다! 마, 가슴도 좀 더 쫙 펴고!","JPN":"あんたはもっと自信持ちいや！　ほら、もっと胸張って！","ENG":"Whatcha need is some self-respect! Keep your chin up!","TWN":"你要對自己更有自信！抬頭挺胸！"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 그럼 우리 타임 캡슐을 만들어 보는 거 어때?","JPN":"あ、じゃあタイムカプセルを作ってみるのはどう？","ENG":"Hey, why don’t we make a time capsule?","TWN":"這樣吧！不如做個時空膠囊怎麼樣？"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오오, 좋네! 나중에 어른이 되면 다 같이 모여가 열어보는기다! 약속이래이!","JPN":"おお、ええやん！　後で大人になったら、みんな集まって開けてみよ！　約束やで！","ENG":"Oh goodie! Y’all are goin’ to gather after we’ve grown up, and we’re gonna open this together! It’s a promise!","TWN":"喔喔，不錯喔！等長大後再一起打開來看！說好囉！"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……저도 좋아요.","JPN":"……僕も賛成です。","ENG":"...Cool with me as well.","TWN":"……我也同意。"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"얘들아. 말이 나와서 말인데, 혹시 너희들은 나중에 크면 뭐가 되고 싶어?","JPN":"みんな。その話のついでなんだけど、みんなは将来何になりたいの？","ENG":"Hey guys, while we're on the subject, what do you want to be when you grow up?","TWN":"說到這個，你們有想過長大後要做什麼嗎？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내 말 안 해줬나? 당연히 쌤 곁에서…","JPN":"言わんかった？　当然先生のそばで……","ENG":"Didn't I say already? I'm gonna be next to Teach and–","TWN":"我沒說過嗎？當然是和老師一起…"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내는… 카운터즈 사가를 최고로 만들기다!","JPN":"ウチ……最っ高のカウンターズ・サーガを作るんや！","ENG":"I'm gonna... make Counters Saga the best game ever!","TWN":"一起…製作最棒的制裁者傳奇！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"엥? 똑같은 게임을 또 만드시게요?","JPN":"えっ？　同じゲームをまた作るんですか？","ENG":"Huh? You're going to make the same game again?","TWN":"蛤？你要做一個一樣的遊戲？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그런 말이 아니고….","JPN":"そうちゃうて……","ENG":"That's not what I'm sayin'...","TWN":"不是這個意思…"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내는 게임 회사 사장이 될 기다!","JPN":"ウチはゲーム会社の社長になる！","ENG":"I'm gonna become a CEO of a game company!","TWN":"我要成為遊戲公司的老闆！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"카운터즈 사가를 대박 내가, 후속작도 내고, 영화도 내고 만화도 다 만들어볼 기다!","JPN":"カウンターズ・サーガを大ヒットさせて、その続編出して、映画もマンガも全部作るんや！","ENG":"Counters Saga is gonna be a huge hit, releasing a sequel, and licensing it out to make movies and comics and all!","TWN":"我要讓制裁者傳奇大賣，然後再出續作，還要出電影，漫畫也要出！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"게임 회사인데 왜 영화에 만화까지 만들어요?","JPN":"ゲーム会社なのに、どうして映画やマンガまで？","ENG":"Why would a game company make movies and comics?","TWN":"遊戲公司幹嘛出電影跟漫畫？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"성공하면 뭐든지 가능한 거 모르나. 그럼 박스 니는 커서 뭐가 되고 싶은데?","JPN":"一発成功させたら、何でもいけるって。ほんならダンボール、あんたは何になりたい？","ENG":"Don't ya know everythin' is possible when you're successful? Then, whaddya wanna be when you grow up, Boxie?","TWN":"只要大賣我想出什麼就出什麼！那不然紙箱你說說看，你長大要做什麼？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L34_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저, 저요?","JPN":"ぼ、僕ですか？","ENG":"M-me?","TWN":"我，我嗎？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"음…. 아무래도 프리랜서 쪽으로 생각하고 있어요.","JPN":"うーん……フリーランサーかなって思ってますね。","ENG":"Mm.... I was thinking of working as a freelancer.","TWN":"嗯…我想當自由工作者。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"평범한 샐러리맨으로 살기엔 인생이 너무 아깝잖아요.","JPN":"普通のサラリーマンって、人生がもったいないじゃないですか。","ENG":"There's so much in life to waste it in being a normal salaryman.","TWN":"只當一個平凡的上班族不是很浪費生命嗎？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오~ 박스 네가 벌써부터 나중 일을 생각했나?","JPN":"お～ダンボール、あんたもう先のこと考えてたんか？","ENG":"Ooh! You're already thinkin' about the future?","TWN":"哇喔～紙箱，你現在就已經在想將來的事啦？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}}]`);export{e as default};